What's the vulnerability here?

```solidity
pragma solidity ^0.8.0;

contract Escrow {
    address public buyer;
    address public seller;
    uint256 public amount;

    function deposit() external payable {
        buyer = msg.sender;
        amount = msg.value;
    }

    function release() external {
        require(msg.sender == buyer);
        payable(seller).transfer(amount);
    }
}
```

assistant:
**Vulnerabilities: Missing Zero-Address Check + State Overwrite on Re-deposit**

1. **`seller` is never set**: if `seller == address(0)` (the default), calling `release()` sends ETH to `address(0)` — the funds are permanently burned.

2. **Deposit overwrites state**: if `deposit()` is called again after the first deposit, `buyer` and `amount` are overwritten with the new caller and value, while the original depositor's ETH is trapped (no way to reclaim it). The original buyer is also replaced and can no longer call `release()`.

**Fix**:
```solidity
constructor(address _seller) {
    require(_seller != address(0), "Zero address");
    seller = _seller;
}

function deposit() external payable {
    require(buyer == address(0), "Already deposited");
    require(msg.value > 0, "No ETH sent");
    buyer = msg.sender;
    amount = msg.value;
}
```

