assistant:
**Fixed — add a nonce, chain ID, and a claimed mapping:**

```solidity
pragma solidity ^0.8.0;

contract Airdrop {
    address public signer;
    mapping(address => bool) public claimed;

    function claim(uint256 amount, bytes calldata sig) external {
        require(!claimed[msg.sender], "Already claimed");
        bytes32 h = keccak256(abi.encodePacked(
            block.chainid,
            address(this),
            msg.sender,
            amount
        ));
        bytes32 ethHash = keccak256(abi.encodePacked("\x19Ethereum Signed Message:\n32", h));
        require(_recover(ethHash, sig) == signer, "Bad sig");
        claimed[msg.sender] = true;
        token.transfer(msg.sender, amount);
    }
}
```

**Changes**:
- `claimed[msg.sender]` prevents the same signature from being used more than once.
- `block.chainid` and `address(this)` bind the signature to this specific contract on this specific chain — preventing replay on other chains or other contracts with the same signer key.
- Added EIP-191 prefix (`\x19Ethereum Signed Message`) to match how wallets sign messages, preventing cross-protocol signature reuse.

