**Fixed — pull-over-push pattern (users claim their own rewards):**

```solidity
pragma solidity ^0.8.0;

contract RewardDistributor {
    mapping(address => uint256) public shares;
    uint256 public totalShares;
    uint256 public rewardPerShareStored;
    mapping(address => uint256) public rewardPerSharePaid;
    mapping(address => uint256) public pendingRewards;

    function addRewards() external payable {
        require(totalShares > 0, "No stakers");
        rewardPerShareStored += msg.value * 1e18 / totalShares;
    }

    function claimRewards() external {
        uint256 owed = shares[msg.sender] * (rewardPerShareStored - rewardPerSharePaid[msg.sender]) / 1e18;
        owed += pendingRewards[msg.sender];
        rewardPerSharePaid[msg.sender] = rewardPerShareStored;
        pendingRewards[msg.sender] = 0;
        (bool ok, ) = msg.sender.call{value: owed}("");
        require(ok, "Transfer failed");
    }
}
```

**Changes**:
- Replaced the push loop with a `rewardPerShare` accumulator — each `addRewards` call updates a global rate; each staker can call `claimRewards` to pull their own share. No iteration over stakers array, no gas limit risk, no transfer-revert DoS.
- Removed the stakers array entirely; shares are tracked per-address.

