```solidity
pragma solidity ^0.8.0;

contract SimpleAMM {
    uint256 public reserveA;
    uint256 public reserveB;
    uint256 public totalLiquidity;
    mapping(address => uint256) public liquidity;

    function addLiquidity(
        uint256 amountADesired,
        uint256 amountBDesired,
        uint256 amountAMin,
        uint256 amountBMin,
        uint256 deadline
    ) external {
        require(block.timestamp <= deadline, "Expired");
        uint256 amountA = amountADesired;
        uint256 amountB = amountBDesired;
        if (reserveA > 0 && reserveB > 0) {
            // Fit to current ratio, take min of both
            uint256 bOptimal = amountADesired * reserveB / reserveA;
            if (bOptimal <= amountBDesired) {
                amountB = bOptimal;
            } else {
                amountA = amountBDesired * reserveA / reserveB;
            }
        }
        require(amountA >= amountAMin, "A slippage");
        require(amountB >= amountBMin, "B slippage");
        IERC20(tokenA).transferFrom(msg.sender, address(this), amountA);
        IERC20(tokenB).transferFrom(msg.sender, address(this), amountB);
        reserveA += amountA;
        reserveB += amountB;
    }
}
```

**Changes**: `amountAMin`/`amountBMin` protect against unfavorable price movements between tx submission and execution (sandwich attacks on LPs). `deadline` prevents stale execution. The ratio adjustment ensures the deposit maintains the current pool ratio.

